CREATE OR REPLACE FUNCTION "public"."mark_no_show_reservations"("reference_time" timestamp with time zone DEFAULT "now"(), "club_timezone" "text" DEFAULT 'Atlantic/Canary'::"text") RETURNS integer LANGUAGE "plpgsql" SECURITY DEFINER SET "search_path" TO '' AS $$ DECLARE updated_count integer; BEGIN UPDATE public.reservations SET status = 'no_show' WHERE status = 'pending' AND activated_at IS NULL AND LEAST(((date::timestamp + start_time::time) AT TIME ZONE club_timezone) + interval '60 minutes', ((date::timestamp + end_time::time) AT TIME ZONE club_timezone)) < reference_time; GET DIAGNOSTICS updated_count = ROW_COUNT; RETURN updated_count; END; $$;
